   223	// Generic binary expression helper
   224	static BinaryExpr::Op tokenToBinaryOp(size_t tokenType)
   225	{
   226	  switch (tokenType) {
   227	    case ast::Plus: return BinaryExpr::kAdd;
   228	    case ast::Minus: return BinaryExpr::kSub;
   229	    case ast::Star: return BinaryExpr::kMul;
   230	    case ast::Slash: return BinaryExpr::kDiv;
   231	    case ast::Percent: return BinaryExpr::kMod;
   232	    case ast::Less: return BinaryExpr::kLt;
   233	    case ast::Greater: return BinaryExpr::kGt;
   234	    case ast::LessEqual: return BinaryExpr::kLe;
   235	    case ast::GreaterEqual: return BinaryExpr::kGe;
   236	    case ast::EqualEqual: return BinaryExpr::kEq;
   237	    case ast::NotEqual: return BinaryExpr::kNe;
   238	    case ast::AndAnd: return BinaryExpr::kAnd;
   239	    case ast::OrOr: return BinaryExpr::kOr;
   240	    case ast::And: return BinaryExpr::kINVALID; // Bitwise AND
   241	    case ast::Or: return BinaryExpr::kINVALID;  // Bitwise OR
   242	    case ast::Xor: return BinaryExpr::kINVALID; // Bitwise XOR
   243	    default: ABORT();
   244	  }
   245	}
