   247	template<typename Ctx>
   248	Expr*
   249	makeBinaryChain(Ast2Asg& ast2asg, Ctx* ctx, BinaryExpr::Op baseOp = BinaryExpr::kINVALID)
   250	{
   251	  auto children = ctx->children;
   252	  auto first = dynamic_cast<decltype(ctx->castExpression(0))>(children[0]);
   253	  (void)first;
   254	  Expr* ret = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[0]));
   255	
   256	  for (unsigned i = 1; i; i < children.size(); ++i) {
   257	    auto node = ast2asg.mMgr.template make<BinaryExpr>();
   258	    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
   259	                   ->getSymbol()->getType();
   260	    auto op = tokenToBinaryOp(token);
   261	    if (op == BinaryExpr::kINVALID) {
   262	      // Handle bitwise ops
   263	      if (token == ast::And) op = BinaryExpr::kINVALID; // We'll skip this
   264	      else ABORT();
   265	    }
   266	    node->op = op;
   267	    node->lft = ret;
   268	    node->rht = ast2asg(dynamic_cast<decltype(ctx->castExpression(0))>(children[++i]));
   269	    ret = node;
   270	  }
   271	  return ret;
   272	}
